import logging
from azure.functions import HttpRequest, HttpResponse
from azure.storage.blob import BlobServiceClient

def main(req: HttpRequest) -> HttpResponse:
    logging.info('Python HTTP trigger function processed a request.')

    # Retrieve the blob path from query parameters
    blob_path = req.params.get('blobPath')
    if not blob_path:
        return HttpResponse("Please provide a blob path in the query string", status_code=400)

    try:
        # Initialize BlobServiceClient using connection string or other authentication method
        connection_string = "your_connection_string_here"
        blob_service_client = BlobServiceClient.from_connection_string(connection_string)
        
        # Split the blob path to get container name and blob name
        parts = blob_path.split('/', 1)
        if len(parts) != 2:
            return HttpResponse("Invalid blob path format", status_code=400)

        container_name, blob_name = parts

        # Get the blob client
        blob_client = blob_service_client.get_blob_client(container=container_name, blob=blob_name)

        # Download the blob content
        blob_data = blob_client.download_blob().readall()

        return HttpResponse(blob_data, status_code=200, mimetype='application/octet-stream')

    except Exception as e:
        logging.error(f"Error reading blob: {e}")
        return HttpResponse("An error occurred while reading the blob", status_code=500)